#include <stdio.h>
#include <stdlib.h>
#define MAX 100
int n, m, u, v, graph[MAX][MAX], parent[MAX];
int bfs(int s, int t) {
    int visited[MAX] = {0};
    int queue[MAX], front = 0, rear = 0;
    queue[rear++] = s;
    visited[s] = 1;
    while (front < rear) {
        int u = queue[front++];
        for (int v = 0; v < n; v++) {
            if (!visited[v] && graph[u][v] > 0) {
                queue[rear++] = v;
                visited[v] = 1;
                parent[v] = u;
                if (v == t) return 1;
            }
        }
    }
    return 0;
}
int fordFulkerson(int s, int t) {
    int max_flow = 0;
    while (bfs(s, t)) {
        int path_flow = 100000;
        int u = t;
        while (u != s) {
            int v = parent[u];
            path_flow = (path_flow < graph[v][u]) ? path_flow : graph[v][u];
            u = v;
        }
        max_flow += path_flow;
        u = t;
        while (u != s) {
            int v = parent[u];
            graph[v][u] -= path_flow;
            graph[u][v] += path_flow;
            u = v;
        }
    }
    return max_flow;
}
int main() {
    scanf("%d %d", &n, &m);
    for (int i = 0; i < m; i++) {
        scanf("%d %d", &u, &v);
        graph[u-1][v-1] = 1;
    }
    printf("%d\n", fordFulkerson(0, n-1));
    return 0;
}

