import java.util.Queue;
import java.util.LinkedList;
public class Main {
    static final int MAX = 100;
    static int n, m, u, v;
    static int[][] graph = new int[MAX][MAX];
    static int[] parent = new int[MAX];
    public static boolean bfs(int s, int t) {
        boolean[] visited = new boolean[MAX];
        Queue<Integer> q = new LinkedList<>();
        q.add(s);
        visited[s] = true;
        while (!q.isEmpty()) {
            int u = q.poll();
            for (int v = 0; v < n; v++) {
                if (!visited[v] && graph[u][v] > 0) {
                    q.add(v);
                    visited[v] = true;
                    parent[v] = u;
                    if (v == t) return true;
                }
            }
        }
        return false;
    }
    public static int fordFulkerson(int s, int t) {
        int max_flow = 0;
        while (bfs(s, t)) {
            int path_flow = 100000;
            int u = t;
            while (u != s) {
                int v = parent[u];
                path_flow = Math.min(path_flow, graph[v][u]);
                u = v;
            }
            max_flow += path_flow;
            u = t;
            while (u != s) {
                int v = parent[u];
                graph[v][u] -= path_flow;
                graph[u][v] += path_flow;
                u = v;
            }
        }
        return max_flow;
    }
    public static void main(String[] args) {
        java.util.Scanner sc = new java.util.Scanner(System.in);
        n = sc.nextInt();
        m = sc.nextInt();
        for (int i = 0; i < m; i++) {
            u = sc.nextInt();
            v = sc.nextInt();
            graph[u-1][v-1] = 1;
        }
        System.out.println(fordFulkerson(0, n-1));
    }
}

